mapper.select:
SELECT id, operator, action_type AS actionType, biz_type AS bizType, biz_no AS bizNo, content, request_path AS requestPath, request_method AS requestMethod, ip, create_time AS createTime FROM xtmd_operation_log
AND operator = #{operator}
AND action_type = #{actionType}
AND create_time >= #{startTime}
AND create_time <= #{endTime}
AND ( operator LIKE CONCAT('%', #{keyword}, '%') OR biz_no LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY create_time DESC, id DESC
